import { GoogleGenAI, Type } from "@google/genai";
import { ScienceReview, TrainingProtocol, ValidationReport, LaunchAsset } from "../types";
import { BRAND_MANIFESTO, VALIDATION_PROMPT_TEMPLATE } from "../constants";

// Schema definition for the expected JSON structure
const reviewSchema = {
  type: Type.OBJECT,
  properties: {
    spotlightTitle: { type: Type.STRING, description: "Viral, catchy title. Simple language." },
    scienceSummary: { type: Type.STRING, description: "Plain English summary, 4th-5th grade level, mentioning the 'holy sh*t' moment." },
    tags: { type: Type.ARRAY, items: { type: Type.STRING }, description: "3-4 relevant tags (e.g. Astro-Performance, MMA, Zero-G, Neuro)" },
    citation: {
      type: Type.OBJECT,
      properties: {
        title: { type: Type.STRING },
        link: { type: Type.STRING },
        authors: { type: Type.STRING },
        date: { type: Type.STRING },
      },
    },
    whyWarriorsCare: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      description: "Two powerful bullet points. 'This means...' format.",
    },
    trainingApplication: {
      type: Type.OBJECT,
      properties: {
        title: { type: Type.STRING },
        coachNotes: { type: Type.STRING },
        rounds: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              duration: { type: Type.STRING },
              description: { type: Type.STRING },
              drill: { type: Type.ARRAY, items: { type: Type.STRING } },
            },
          },
        },
      },
    },
    action: {
      type: Type.OBJECT,
      properties: {
        text: { type: Type.STRING },
        keyword: { type: Type.STRING },
      },
    },
    appendix: {
      type: Type.OBJECT,
      properties: {
        methodology: { type: Type.STRING },
        findings: { type: Type.STRING },
        implications: { type: Type.STRING },
        context: { type: Type.STRING },
      },
    },
  },
};

const validationSchema = {
  type: Type.OBJECT,
  properties: {
    overallQuality: { type: Type.STRING },
    scientificVerification: { type: Type.STRING },
    biomechanicsCheck: { type: Type.STRING },
    brandVoiceCheck: { type: Type.STRING },
    correctedContent: { type: Type.STRING },
    socialAssets: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          platform: { type: Type.STRING },
          caption: { type: Type.STRING },
          visualIdea: { type: Type.STRING },
        },
      },
    },
  },
};

const launchSchema = {
  type: Type.OBJECT,
  properties: {
    assets: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          platform: { type: Type.STRING, enum: ['LINKEDIN', 'INSTAGRAM', 'TWITTER', 'EMAIL'] },
          content: { type: Type.STRING },
          visualCue: { type: Type.STRING },
          hashtags: { type: Type.ARRAY, items: { type: Type.STRING } },
        }
      }
    }
  }
};

export const generateScienceReview = async (topicOrAbstract: string): Promise<ScienceReview | null> => {
  if (!process.env.API_KEY) {
    console.error("API Key is missing");
    return null;
  }

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const prompt = `
      You are the Lead Scientist for "G-FORCE SCIENCE" and "SD4ALL".

      ${BRAND_MANIFESTO}

      YOUR MISSION:
      Decode human performance research for the "Everyday Warrior" (Adults, 35-65) and "Extreme Explorer" (Astronauts, Operators).
      Generate a structured JSON response matching the provided schema.

      TONE RULES:
      - 4th-5th grade readability.
      - "Space Age meets Stone Age".
      - Dry humor is good.
      - NO macho nonsense. NO "Alpha".
      - Focus on CAPABILITY.

      INPUT DATA:
      "${topicOrAbstract}"
    `;

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: reviewSchema,
        temperature: 0.7, 
      },
    });

    const text = response.text;
    if (!text) return null;

    const data = JSON.parse(text);
    return { ...data, id: `gen-${Date.now()}` };

  } catch (error) {
    console.error("Gemini generation error:", error);
    return null;
  }
};

export const validateReview = async (review: ScienceReview): Promise<ValidationReport | null> => {
  if (!process.env.API_KEY) return null;

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const contentToValidate = JSON.stringify(review);

    const prompt = `
      ${VALIDATION_PROMPT_TEMPLATE}

      CONTENT TO REVIEW:
      ${contentToValidate}
    `;

    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview", // Use Pro for deep reasoning/validation
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: validationSchema,
      },
    });

    if (response.text) {
      return JSON.parse(response.text);
    }
    return null;
  } catch (error) {
    console.error("Validation error:", error);
    return null;
  }
};

export const generateLaunchAssets = async (): Promise<LaunchAsset[]> => {
  if (!process.env.API_KEY) return [];

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const prompt = `
      You are the Communications Director for Gonçalo Esteves (Founder of SD4ALL / G-Force Science).

      CONTEXT:
      Gonçalo is pivoting his brand today.
      FROM: Local Martial Arts Studio owner.
      TO: "G-Force Science" - A global platform combining Space Science, Self-Defense, and Human Performance.

      IDENTITY:
      ${BRAND_MANIFESTO}

      TASK:
      Write the OFFICIAL LAUNCH POSTS for today.

      1. LINKEDIN: Personal, story-driven. "Why I am looking at space to teach self-defense." Professional but visionary.
      2. INSTAGRAM: Punchy, visual, high energy.
      3. TWITTER: A short thread (just give the main body) about "The 3 things Astronauts know about pressure that we don't."
      4. EMAIL: To the existing email list (65 members). Reassure them the gym isn't closing, but evolving.

      TONE:
      Humble, authoritative, "Space Age meets Stone Age".
    `;

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: launchSchema,
      },
    });

    if (response.text) {
      const data = JSON.parse(response.text);
      return data.assets;
    }
    return [];
  } catch (error) {
    console.error("Launch asset generation error:", error);
    return [];
  }
};

export const generateProtocolVideo = async (protocol: TrainingProtocol): Promise<string> => {
  if (typeof window !== 'undefined' && (window as any).aistudio) {
    const hasKey = await (window as any).aistudio.hasSelectedApiKey();
    if (!hasKey) {
      throw new Error("API_KEY_REQUIRED");
    }
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const actionSummary = protocol.rounds.map(r => r.drill[0]).join(". ");
  const prompt = `Cinematic video of a tactical athlete in a futuristic, clean dojo environment performing: ${protocol.title}. Movements: ${actionSummary}. Lighting: Cinematic Blue and Steel Gray. Style: Realistic, 4k, serious but calm.`;

  try {
    let operation = await ai.models.generateVideos({
      model: 'veo-3.1-fast-generate-preview',
      prompt: prompt,
      config: {
        numberOfVideos: 1,
        resolution: '720p',
        aspectRatio: '16:9'
      }
    });

    while (!operation.done) {
      await new Promise(resolve => setTimeout(resolve, 5000));
      operation = await ai.operations.getVideosOperation({operation: operation});
    }

    const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
    if (!downloadLink) {
      throw new Error("No video URI returned");
    }

    const videoResponse = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
    const videoBlob = await videoResponse.blob();
    return URL.createObjectURL(videoBlob);

  } catch (error) {
    console.error("Video generation failed", error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { generateLaunchAssets } from '../services/geminiService';
import { LaunchAsset } from '../types';
import { Rocket, Linkedin, Instagram, Twitter, Mail, Copy, Check, Loader2 } from 'lucide-react';

const LaunchKit: React.FC = () => {
  const [assets, setAssets] = useState<LaunchAsset[]>([]);
  const [loading, setLoading] = useState(true);
  const [copiedIndex, setCopiedIndex] = useState<number | null>(null);

  useEffect(() => {
    const loadAssets = async () => {
      const generated = await generateLaunchAssets();
      setAssets(generated);
      setLoading(false);
    };
    loadAssets();
  }, []);

  const handleCopy = (text: string, index: number) => {
    navigator.clipboard.writeText(text);
    setCopiedIndex(index);
    setTimeout(() => setCopiedIndex(null), 2000);
  };

  const getIcon = (platform: string) => {
    switch (platform) {
      case 'LINKEDIN': return <Linkedin className="w-5 h-5 text-blue-500" />;
      case 'INSTAGRAM': return <Instagram className="w-5 h-5 text-pink-500" />;
      case 'TWITTER': return <Twitter className="w-5 h-5 text-blue-400" />;
      case 'EMAIL': return <Mail className="w-5 h-5 text-yellow-500" />;
      default: return <Rocket className="w-5 h-5" />;
    }
  };

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center h-96">
        <Loader2 className="w-12 h-12 text-brand-blue animate-spin mb-4" />
        <h3 className="text-xl font-display font-bold text-white animate-pulse">INITIATING LAUNCH SEQUENCE</h3>
        <p className="text-gray-500 mt-2">Drafting official comms for all channels...</p>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto p-6 animate-fadeIn">
      <div className="flex items-center gap-3 mb-8">
        <div className="bg-brand-blue p-2 rounded-full shadow-[0_0_20px_rgba(28,109,208,0.5)]">
          <Rocket className="w-6 h-6 text-white" />
        </div>
        <div>
          <h2 className="text-3xl font-display font-bold text-white">LAUNCH COMMAND</h2>
          <p className="text-gray-400">Official "Go Live" Assets • {new Date().toLocaleDateString()}</p>
        </div>
      </div>

      <div className="grid gap-8">
        {assets.map((asset, idx) => (
          <div key={idx} className="bg-brand-gray/30 border border-gray-700 rounded-lg p-6 hover:border-brand-blue transition-colors">
            <div className="flex justify-between items-center mb-4">
              <div className="flex items-center gap-2">
                {getIcon(asset.platform)}
                <h3 className="text-lg font-bold text-white uppercase tracking-wider">{asset.platform}</h3>
              </div>
              <button
                onClick={() => handleCopy(asset.content, idx)}
                className="flex items-center gap-2 text-xs font-bold uppercase tracking-wider text-gray-400 hover:text-white transition-colors bg-brand-black px-3 py-1.5 rounded border border-gray-700"
              >
                {copiedIndex === idx ? (
                  <> <Check className="w-3 h-3 text-green-500" /> Copied </>
                ) : (
                  <> <Copy className="w-3 h-3" /> Copy Text </>
                )}
              </button>
            </div>

            <div className="bg-brand-black/50 p-4 rounded border border-gray-800 font-mono text-sm text-gray-300 whitespace-pre-wrap mb-4">
              {asset.content}
            </div>

            <div className="flex flex-col md:flex-row gap-4 text-xs text-gray-500">
              <div className="flex-1">
                <span className="text-brand-blue font-bold uppercase block mb-1">Visual Directive:</span>
                {asset.visualCue}
              </div>
              <div className="flex-1">
                <span className="text-brand-blue font-bold uppercase block mb-1">Hashtags:</span>
                {asset.hashtags.join(" ")}
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default LaunchKit;

