      </div>
    </main>
  );

  return (
    <div className="min-h-screen bg-brand-black text-brand-white font-sans selection:bg-brand-blue selection:text-white">
      {renderHeader()}

      {viewMode === ViewMode.DASHBOARD && renderDashboard()}

      {viewMode === ViewMode.DETAILS && activeReview && renderDetailView(activeReview)}

      {viewMode === ViewMode.GENERATOR && (
        <Generator 
          onReviewGenerated={handleReviewGenerated} 
          onCancel={() => setViewMode(ViewMode.DASHBOARD)} 
        />
      )}

      {viewMode === ViewMode.LAUNCH_KIT && (
