      )}

      {/* Mobile Menu Overlay */}
      {mobileMenuOpen && (
        <div className="fixed inset-0 z-40 bg-brand-black p-4 pt-20 md:hidden">
          <nav className="flex flex-col space-y-4 text-lg font-bold text-gray-300">
