import { GoogleGenAI, Type } from "@google/genai";
import { ScienceReview, TrainingProtocol, ValidationReport, LaunchAsset, SpaceSignal } from "../types";
import { BRAND_MANIFESTO } from "../constants";

const signalSchema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING },
    deorbitedInsight: { type: Type.STRING, description: "Translation of space news into human tactics. Direct and actionable." },
    relevance: { type: Type.STRING, enum: ['PERSONAL', 'COMPANY', 'DESIRES'] },
    suggestedProtocolTopic: { type: Type.STRING }
  }
};

export const deorbitSignal = async (newsText: string): Promise<Partial<SpaceSignal> | null> => {
  if (!process.env.API_KEY) return null;
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    ${BRAND_MANIFESTO}

    DE-ORBIT MISSION:
    Take this Space News and translate it into a Human Performance Tactic.
    What can a person or company IMPLEMENT today based on this astronaut/space news?

    NEWS:
    "${newsText}"
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: signalSchema,
      },
    });
    return response.text ? JSON.parse(response.text) : null;
  } catch (error) {
    console.error(error);
    return null;
  }
};

export const generateBroadcastScript = async (signals: SpaceSignal[]): Promise<string> => {
  if (!process.env.API_KEY) return "No Signal.";
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    ACT AS: Gonçalo Esteves, Host of "GE-FORCE LIVE".
    ${BRAND_MANIFESTO}

    INPUT SIGNALS:
    ${JSON.stringify(signals)}

    TASK:
    Write a punchy, high-speed broadcast script (300 words).
    - Open with a "Comms Check".
    - Go through the news aggregator style (like Greg Isenberg/Kevin Rose tech memes).
    - End with a "Human Implementation" protocol.
    - Style: Direct, tactical, slightly dry humor.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash",
    contents: prompt,
  });
  return response.text || "Broadcast failed.";
};

