const SignalIngest: React.FC<Props> = ({ onSignalAdded }) => {
  const [news, setNews] = useState('');
  const [loading, setLoading] = useState(false);

  const handleIngest = async () => {
    if (!news) return;
    setLoading(true);
    const data = await deorbitSignal(news);
    if (data) {
      onSignalAdded({
        id: `sig-${Date.now()}`,
        title: data.title || 'Unknown Event',
        source: 'User Feed',
        timestamp: new Date().toISOString().split('T')[0],
        rawNews: news,
        deorbitedInsight: data.deorbitedInsight || '',
        relevance: data.relevance || 'PERSONAL'
      });
      setNews('');
    }
    setLoading(false);
  };

  return (
    <div className="max-w-2xl mx-auto p-6">
      <div className="bg-brand-gray border border-brand-blue/30 rounded-lg p-8 hud-glow">
        <h2 className="text-2xl font-display font-bold text-white mb-6 flex items-center gap-3">
