    }
  }

  // Guidelines: Create new instance right before making the call
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `A cinematic, high-intensity training demonstration for a protocol titled: ${protocol.title}. 
  The video shows an elite athlete in a futuristic, low-light tactical environment performing high-readiness movements. 
  Style: Gritty, 8k resolution, tactical, space-inspired lighting, photorealistic.`;

  try {
    let operation = await ai.models.generateVideos({
      model: 'veo-3.1-fast-generate-preview',
      prompt: prompt,
      config: {
        numberOfVideos: 1,
        resolution: '1080p',
        aspectRatio: '16:9'
      }
    });

    while (!operation.done) {
      await new Promise(resolve => setTimeout(resolve, 10000));
      operation = await ai.operations.getVideosOperation({ operation: operation });
    }

    const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
    if (!downloadLink) throw new Error("Video generation failed.");

    // Return URL with API key appended as per fetch guidelines
    return `${downloadLink}&key=${process.env.API_KEY}`;
  } catch (error) {
    console.error(error);
    throw error;
  }
};

