      onSignalAdded({
        id: `sig-${Date.now()}`,
        title: data.title || (isPRD ? 'Requirement Analysis' : 'News Intel'),
        source: isPRD ? 'Technical PRD' : 'News Feed',
        timestamp: new Date().toISOString().split('T')[0],
        rawNews: news.substring(0, 500) + '...',
        deorbitedInsight: data.deorbitedInsight || '',
        relevance: data.relevance || 'PERSONAL',
        isAnalyzedPRD: isPRD
      });
      setNews('');
    }
    setLoading(false);
  };

  return (
    <div className="max-w-3xl mx-auto p-6 animate-fadeIn">
      <div className="bg-brand-gray border border-gray-800 rounded-lg p-8 relative overflow-hidden">
        <div className="scan-line"></div>
        <div className="flex justify-between items-center mb-8">
          <h2 className="text-2xl font-display font-bold text-white flex items-center gap-3">
            <Satellite className="text-brand-blue" /> SIGNAL_INGESTION
          </h2>
          <div className="flex items-center gap-4">
             <label className="flex items-center gap-2 cursor-pointer group">
                <input 
                  type="checkbox" 
                  checked={isPRD} 
                  onChange={(e) => setIsPRD(e.target.checked)} 
                  className="hidden" 
                />
                <div className={`w-10 h-5 rounded-full p-1 transition-colors ${isPRD ? 'bg-brand-blue' : 'bg-gray-700'}`}>
                  <div className={`w-3 h-3 bg-white rounded-full transition-transform ${isPRD ? 'translate-x-5' : ''}`}></div>
                </div>
                <span className={`text-[10px] font-bold uppercase tracking-widest ${isPRD ? 'text-white' : 'text-gray-500'}`}>Technical PRD Mode</span>
             </label>
          </div>
        </div>

        <div className="mb-6">
          <div className="flex justify-between items-center mb-2">
            <label className="text-[10px] font-bold text-gray-500 uppercase tracking-widest flex items-center gap-1">
              <Clipboard className="w-3 h-3" /> Raw Input Data
            </label>
            <span className="text-[10px] text-gray-600 font-mono">{news.length} chars</span>
          </div>
          <textarea 
            className="w-full h-64 bg-brand-black border border-gray-800 rounded p-6 text-gray-300 font-mono text-sm focus:outline-none focus:border-brand-blue transition-all resize-none shadow-inner"
            placeholder={isPRD ? "Paste your technical PRD / Requirement doc text here..." : "Paste space news, newsletter text, or tweets..."}
            value={news}
            onChange={(e) => setNews(e.target.value)}
          />
        </div>

        <div className="bg-brand-blue/5 border border-brand-blue/20 p-4 rounded mb-6 flex gap-3 items-start">
          <Info className="w-5 h-5 text-brand-blue shrink-0 mt-0.5" />
          <p className="text-xs text-gray-400 leading-relaxed">
            {isPRD 
              ? "PRD Mode: The system will focus on extracting engineering requirements and translating them into physical or cognitive performance protocols for operators."
              : "News Mode: High-speed summarization focusing on how aerospace events impact human psychology and business strategy."}
          </p>
        </div>

        <button 
          onClick={handleIngest}
          disabled={loading || !news}
          className="w-full bg-brand-blue hover:bg-blue-600 text-white font-bold py-4 rounded uppercase tracking-widest flex items-center justify-center gap-2 shadow-lg transition-all active:scale-95 disabled:opacity-50"
        >
          {loading ? <Loader2 className="animate-spin w-5 h-5" /> : <Zap className="w-5 h-5" />}
          {isPRD ? 'DE-ORBIT PRD REQUIREMENTS' : 'PROCESS INTELLIGENCE'}
        </button>
      </div>
    </div>
  );
};

