    Take the following input (could be a PRD, a news article, or a tweet thread).
    Identify the "Core Requirement" and translate it into a "Human Implementation Tactic".

    INPUT DATA:
    "${newsText}"
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: signalSchema,
      },
    });
    return response.text ? JSON.parse(response.text) : null;
  } catch (error) {
