/**
 * Generates a tactical video demonstration of a training protocol using Veo.
 */
export const generateProtocolVideo = async (protocol: TrainingProtocol): Promise<string> => {
  // Check for API key selection for Veo models as per security requirements
  if (typeof window !== 'undefined' && (window as any).aistudio) {
    const hasKey = await (window as any).aistudio.hasSelectedApiKey();
    if (!hasKey) {
      throw new Error('API_KEY_REQUIRED');
    }
  }

  // Create instance right before the call to ensure latest API key is used
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `A cinematic, high-fidelity tactical training demonstration of the "${protocol.title}" protocol. The scene is a futuristic space-age training facility. Show professional operators performing drills: ${protocol.rounds.map(r => r.name).join(', ')}. Atmosphere is focused and high-performance.`;

  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: prompt,
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio: '16:9'
    }
  });

  // Polling for video generation completion as Veo operations are asynchronous
  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 10000));
    operation = await ai.operations.getVideosOperation({ operation: operation });
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
  // Append API key for direct fetching of the video resource from the provided URI
  return `${downloadLink}&key=${process.env.API_KEY}`;
};

